import classes from "./DirectMessageItem.module.css";
import FriendsIcon from "./FriendsIcon";

const DirectMessageItem = (props) => {
  return (
    <li className={classes["item-wrapper"]}>
      <div className={classes["link-button"]}>
        <a className={classes["link"]} href="/">
          <div className={classes["content-layout"]}>
            <div className={classes["avatar"]}>
              {props.children}
              <FriendsIcon className={classes["button-icon"]}></FriendsIcon>
            </div>
            <div className={classes["text"]}>Friends</div>
          </div>
        </a>
      </div>
    </li>
  );
};

export default DirectMessageItem;
